import React, { useState, useEffect } from 'react';
import { motion } from 'framer-motion';
import { Plus, Trash2, X } from 'lucide-react';
import API from '../../utils/api';
import AdminLayout from './AdminLayout';
import toast from 'react-hot-toast';

const GOALS = ['weight-loss','muscle-gain','maintenance','endurance','general'];
const MEAL_TYPES = ['breakfast','lunch','dinner','snack','pre-workout','post-workout'];

const emptyForm = { title: '', description: '', goal: 'general', totalCalories: '', totalProtein: '', isPublic: true };

export default function AdminDiet() {
  const [plans, setPlans] = useState([]);
  const [loading, setLoading] = useState(true);
  const [modal, setModal] = useState(false);
  const [form, setForm] = useState(emptyForm);
  const [meals, setMeals] = useState([]);
  const [imageFile, setImageFile] = useState(null);
  const [saving, setSaving] = useState(false);

  const load = () => API.get('/diet').then(r => setPlans(r.data)).catch(() => {}).finally(() => setLoading(false));
  useEffect(load, []);

  const addMeal = () => setMeals(prev => [...prev, { mealType: 'breakfast', time: '', notes: '', items: [{ name: '', quantity: '', calories: '' }] }]);
  const updateMeal = (i, field, val) => setMeals(prev => prev.map((m, idx) => idx === i ? { ...m, [field]: val } : m));
  const addMealItem = (i) => setMeals(prev => prev.map((m, idx) => idx === i ? { ...m, items: [...m.items, { name: '', quantity: '', calories: '' }] } : m));
  const updateMealItem = (mi, ii, field, val) => setMeals(prev => prev.map((m, idx) => idx === mi ? { ...m, items: m.items.map((it, jdx) => jdx === ii ? { ...it, [field]: val } : it) } : m));
  const removeMeal = (i) => setMeals(prev => prev.filter((_, idx) => idx !== i));

  const handleSave = async () => {
    if (!form.title) { toast.error('Title required'); return; }
    setSaving(true);
    try {
      const data = new FormData();
      Object.entries(form).forEach(([k, v]) => data.append(k, v));
      data.append('meals', JSON.stringify(meals));
      data.append('assignedTo', JSON.stringify([]));
      if (imageFile) data.append('image', imageFile);
      await API.post('/diet', data, { headers: { 'Content-Type': 'multipart/form-data' } });
      toast.success('Diet plan created!');
      setModal(false); setForm(emptyForm); setMeals([]); setImageFile(null); load();
    } catch { toast.error('Error saving'); }
    finally { setSaving(false); }
  };

  const handleDelete = async (id) => {
    if (!window.confirm('Delete this plan?')) return;
    try { await API.delete(`/diet/${id}`); toast.success('Deleted'); load(); }
    catch { toast.error('Error deleting'); }
  };

  return (
    <AdminLayout title="Diet Plans Management">
      <div className="flex justify-end mb-6">
        <button onClick={() => { setModal(true); setForm(emptyForm); setMeals([]); }} className="btn-fire flex items-center gap-2 text-sm py-2.5 px-4">
          <Plus size={16} /> Add Diet Plan
        </button>
      </div>

      {loading ? (
        <div className="flex justify-center py-20"><div className="w-10 h-10 border-2 border-orange-500 border-t-transparent rounded-full animate-spin" /></div>
      ) : plans.length === 0 ? (
        <div className="text-center py-20 text-gray-500">No diet plans yet.</div>
      ) : (
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
          {plans.map(p => (
            <div key={p._id} className="glass rounded-xl overflow-hidden">
              {p.image && <img src={p.image} alt={p.title} className="w-full h-36 object-cover" />}
              <div className="p-4">
                <div className="flex items-start justify-between">
                  <div>
                    <h3 className="text-white font-semibold">{p.title}</h3>
                    <span className="text-xs text-orange-400 capitalize">{p.goal?.replace('-', ' ')}</span>
                  </div>
                  <button onClick={() => handleDelete(p._id)} className="p-1.5 text-red-400 hover:bg-red-400/10 rounded-lg"><Trash2 size={15} /></button>
                </div>
                <p className="text-gray-500 text-xs mt-2 line-clamp-2">{p.description}</p>
                <div className="flex gap-2 mt-2 text-xs text-gray-500">
                  {p.totalCalories && <span>🔥 {p.totalCalories} kcal</span>}
                  <span>{p.meals?.length || 0} meals</span>
                  {!p.isPublic && <span className="text-yellow-400">🔒 Private</span>}
                </div>
              </div>
            </div>
          ))}
        </div>
      )}

      {modal && (
        <div className="fixed inset-0 z-50 bg-black/60 backdrop-blur-sm flex items-center justify-center px-4">
          <motion.div initial={{ opacity: 0, scale: 0.95 }} animate={{ opacity: 1, scale: 1 }}
            className="bg-[#0d0d14] border border-white/10 rounded-2xl p-6 w-full max-w-3xl max-h-[90vh] overflow-y-auto">
            <div className="flex items-center justify-between mb-5">
              <h2 className="text-white font-bold text-xl">Create Diet Plan</h2>
              <button onClick={() => setModal(false)}><X size={20} className="text-gray-400" /></button>
            </div>
            <div className="grid grid-cols-1 sm:grid-cols-2 gap-4 mb-5">
              <div className="sm:col-span-2">
                <label className="text-gray-400 text-xs block mb-1">Title *</label>
                <input className="input-dark text-sm py-2" value={form.title} onChange={e => setForm({ ...form, title: e.target.value })} placeholder="e.g. Summer Shred Diet" />
              </div>
              <div>
                <label className="text-gray-400 text-xs block mb-1">Goal</label>
                <select className="input-dark text-sm py-2" value={form.goal} onChange={e => setForm({ ...form, goal: e.target.value })}>
                  {GOALS.map(g => <option key={g} value={g} className="bg-[#0d0d14] capitalize">{g.replace('-',' ')}</option>)}
                </select>
              </div>
              <div>
                <label className="text-gray-400 text-xs block mb-1">Visibility</label>
                <div className="flex gap-3 items-center h-10">
                  {[{ v: true, l: 'Public' }, { v: false, l: 'Private' }].map(opt => (
                    <label key={opt.l} className="flex items-center gap-1.5 cursor-pointer">
                      <input type="radio" checked={form.isPublic === opt.v} onChange={() => setForm({ ...form, isPublic: opt.v })} />
                      <span className="text-gray-300 text-xs">{opt.l}</span>
                    </label>
                  ))}
                </div>
              </div>
              <div>
                <label className="text-gray-400 text-xs block mb-1">Total Calories</label>
                <input className="input-dark text-sm py-2" type="number" value={form.totalCalories} onChange={e => setForm({ ...form, totalCalories: e.target.value })} placeholder="2000" />
              </div>
              <div>
                <label className="text-gray-400 text-xs block mb-1">Total Protein</label>
                <input className="input-dark text-sm py-2" value={form.totalProtein} onChange={e => setForm({ ...form, totalProtein: e.target.value })} placeholder="150g" />
              </div>
              <div className="sm:col-span-2">
                <label className="text-gray-400 text-xs block mb-1">Description</label>
                <textarea className="input-dark text-sm min-h-[60px]" value={form.description} onChange={e => setForm({ ...form, description: e.target.value })} />
              </div>
              <div>
                <label className="text-gray-400 text-xs block mb-1">Cover Image</label>
                <input type="file" accept="image/*" onChange={e => setImageFile(e.target.files[0])} className="text-gray-400 text-xs" />
              </div>
            </div>

            {/* Meals */}
            <div className="border-t border-white/10 pt-5">
              <div className="flex items-center justify-between mb-3">
                <h3 className="text-white font-semibold">Meals</h3>
                <button onClick={addMeal} className="flex items-center gap-1.5 text-orange-400 text-xs hover:text-orange-300 border border-orange-500/30 px-3 py-1.5 rounded-lg">
                  <Plus size={13} /> Add Meal
                </button>
              </div>
              {meals.map((meal, mi) => (
                <div key={mi} className="bg-white/3 rounded-xl p-4 mb-3 border border-white/5">
                  <div className="flex items-center justify-between mb-3">
                    <select className="input-dark text-xs py-1.5 w-36" value={meal.mealType} onChange={e => updateMeal(mi, 'mealType', e.target.value)}>
                      {MEAL_TYPES.map(t => <option key={t} value={t} className="bg-[#0d0d14] capitalize">{t}</option>)}
                    </select>
                    <input className="input-dark text-xs py-1.5 w-24 ml-2" placeholder="Time e.g. 8 AM" value={meal.time} onChange={e => updateMeal(mi, 'time', e.target.value)} />
                    <button onClick={() => removeMeal(mi)} className="text-red-400 ml-auto p-1"><X size={14} /></button>
                  </div>
                  {meal.items.map((item, ii) => (
                    <div key={ii} className="flex gap-2 mb-2">
                      <input className="input-dark text-xs py-1.5 flex-1" placeholder="Food item" value={item.name} onChange={e => updateMealItem(mi, ii, 'name', e.target.value)} />
                      <input className="input-dark text-xs py-1.5 w-20" placeholder="Qty" value={item.quantity} onChange={e => updateMealItem(mi, ii, 'quantity', e.target.value)} />
                      <input className="input-dark text-xs py-1.5 w-16" placeholder="kcal" type="number" value={item.calories} onChange={e => updateMealItem(mi, ii, 'calories', e.target.value)} />
                    </div>
                  ))}
                  <button onClick={() => addMealItem(mi)} className="text-orange-400 text-xs hover:underline">+ Add item</button>
                  <input className="input-dark text-xs py-1.5 mt-2" placeholder="Notes (optional)" value={meal.notes} onChange={e => updateMeal(mi, 'notes', e.target.value)} />
                </div>
              ))}
            </div>

            <div className="flex justify-end gap-3 mt-5">
              <button onClick={() => setModal(false)} className="px-4 py-2 text-gray-400 border border-white/10 rounded-lg text-sm">Cancel</button>
              <button onClick={handleSave} disabled={saving} className="btn-fire px-5 py-2 text-sm">
                {saving ? <span className="w-4 h-4 border-2 border-white border-t-transparent rounded-full animate-spin inline-block" /> : 'Save Plan'}
              </button>
            </div>
          </motion.div>
        </div>
      )}
    </AdminLayout>
  );
}
